#### 直接通过 awk 读取文件，然后在 NF字段数 的范围内通过 $i 下标遍历

awk '{
    for (i = 1; i <= NF; i++) {
        seen[$i]++
    }
}
END {
    for (w in seen)
        print w, seen[w]
}' "$1"

#### 2. awk

ls -l | awk '
NR > 1 { sum[$4] += $5 }
END {
    for (g in sum)
        print g, sum[g]
}'

#### 所以用 gsed 使用 Linux 的 GNU sed

gsed -i '/30/d' "$p"

reset

#### }' "$p"

awk '{
    for (i=1;i<=NF;i++){
        $i = toupper($i)
    }
    print
}' "$p" > tmp

#### 或者一口气直接全转了，因为toupper支持

awk '{
    print toupper($0)
}' "$p" > tmp
mv tmp "$p"

reset

#### 3

echo "=== 3"
awk '{
    for (i=1;i<=NF;i++){
        if ( $i ~ /^.s.*/)
            print $i
    }
}' "$p"

#### 4

echo "
=== 4"
awk '{
    for (i=1;i<=NF;i++){
        if ( $i ~ /^[tsh].*/ )
            print $i
    }
}' "$p"

#### awk 要用 /i+/ 还不如 grep

echo "=== 1 - grep"

#### 先拆为一个个单词（包不包含下划线都行）

grep -Eo '[[:alnum:]_]+' "$p" | grep '\(.\)\1\{2,\}'

echo "
=== 1 - awk"

#### 或者手动判断连续，但是本题应该不是希望手动判断

awk '{
    for (i = 1; i <= NF; i++) {
        word = $i
        cnt = 1
        found = 0

        for (j = 2; j <= length(word); j++) {
            if (substr(word, j, 1) == substr(word, j - 1, 1)) {
                cnt++
                if (cnt >= 3) {
                    found = 1
                    break
                }
            } else {
                cnt = 1
            }
        }

        if (found)
            print word
    }
}' "$p"

#### grep 配合 管道化

grep 'a' "$p" | grep 'e' | grep 'i' | grep 'o' | grep 'u'

awk '/a/ && /e/ && /i/ && /o/ && /u/' "$p"

#### }" "$p"

grep '^.*\b.*\b.*$' "$p"

#### Shell 中的变量无法 awk 中无法直接用，得通过 v 传入

awk -v bei="$bei" -v zhu="$zhu" '{
    gsub(bei,zhu,$0)
    print
}' "$p" > tmp
mv tmp "$p"

#### bash ./09 2 04.sh ./test files/09 2.txt

grep -E '\<([[:alnum:]_]+)\>.*\<\1\>.*\<\1\>' "$1"

echo "
=== awk"

#### 感觉用 awk 统计更自然

awk '{
    delete cnt # 如果想换行的话不 delete 重置就好
    for (i = 1; i <= NF; i++) {
        cnt[$i]++
        if (cnt[$i] == 3) {
            print
            break
        }
    }
}' "$1"
